// Helper: generate IDs
let idCounter = 100;
function generateId() {
  return String(++idCounter);
}

// DataLoader-like batching helpers to mitigate N+1 in nested queries
function getPostsByAuthorId(authorId) {
  return Array.from(db.posts.values()).filter(p => p.authorId === authorId);
}

function getCommentsByPostId(postId) {
  return Array.from(db.comments.values()).filter(c => c.postId === postId);
}

function getCommentsByAuthorId(authorId) {
  return Array.from(db.comments.values()).filter(c => c.authorId === authorId);
}

function getReplies(parentCommentId) {
  return Array.from(db.comments.values()).filter(c => c.parentCommentId === parentCommentId);
}

// Query depth and complexity limiting utility
