// Custom depth limiting validation rule
function depthLimitRule(maxDepth) {
  return function (context) {
    const { definitions } = context.getDocument();
    const fragments = {};

    definitions.forEach(def => {
      if (def.kind === 'FragmentDefinition') {
        fragments[def.name.value] = def;
      }
    });

    function getDepth(selectionSet, currentDepth, fragmentSpreads = new Set()) {
      if (!selectionSet) return currentDepth;

      let maxFound = currentDepth;

      for (const selection of selectionSet.selections) {
        if (selection.kind === 'Field') {
          if (selection.selectionSet) {
            const childDepth = getDepth(selection.selectionSet, currentDepth + 1, fragmentSpreads);
            if (childDepth > maxFound) maxFound = childDepth;
          }
        } else if (selection.kind === 'FragmentSpread') {
          const name = selection.name.value;
          if (!fragmentSpreads.has(name)) {
            fragmentSpreads.add(name);
            const fragment = fragments[name];
            if (fragment) {
              const childDepth = getDepth(fragment.selectionSet, currentDepth, fragmentSpreads);
              if (childDepth > maxFound) maxFound = childDepth;
            }
          }
        } else if (selection.kind === 'InlineFragment') {
          const childDepth = getDepth(selection.selectionSet, currentDepth, fragmentSpreads);
          if (childDepth > maxFound) maxFound = childDepth;
        }
      }

      return maxFound;
    }

    return {
      OperationDefinition(node) {
        const depth = getDepth(node.selectionSet, 0);
        if (depth > maxDepth) {
          context.reportError(
            new (require('graphql').GraphQLError)(
              `Query depth of ${depth} exceeds maximum allowed depth of ${maxDepth}. ` +
              `Please reduce nesting or use pagination to fetch nested data in separate queries.`
            )
          );
        }
      },
    };
  };
}

